import { Button,  FormControlLabel, TextField } from '@material-ui/core'
import Checkbox from '@material-ui/core/Checkbox';
import React from 'react'
import { useState } from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { selectUser } from '../../features/userSlice'
import StarIcon from '@material-ui/icons/Star';
import styled from 'styled-components'
import Rating from '@material-ui/lab/Rating';
import Box from '@material-ui/core/Box';
import { db } from '../../components/firebase';
import { selectError, showErrorIsTrue } from '../../features/errorSlice';
import firebase from 'firebase'

export default function FormReviewSection({cursor}) {
    const user = useSelector(selectUser)
    const [disabled, setDisabled] = useState(false)
    const dispatch = useDispatch()
    const [name, setName] = useState((user && user?.displayName) || '')
    const [message, setMessage] = useState('')
    const [asPublic, setAsPublic] = useState(false)
    const [rating, setRating] = useState(null)

    const handleSubmit = e => {
        e.preventDefault()
        if (!user) {
            dispatch(selectError('Trebuie să te autentifici mai întâi❌'));
            dispatch(showErrorIsTrue())
            return
        }

        db.collection('cm-reviews').doc(user?.email).set({
            name: name,
            email: user?.email,
            photo: user?.photoUrl,
            message: message,
            public: asPublic,
            rating: Number(rating),
            read: false,
            timestamp: firebase.firestore.FieldValue.serverTimestamp()
        })

        dispatch(selectError(`Recenzie ${asPublic ? 'postată' : 'trimisă'}✅`));
        dispatch(showErrorIsTrue())

        setName('')
        setMessage('')
        setAsPublic(false)
        setRating(null)

        setDisabled(true)
    }

    const handleEnter = () => {
        cursor.current.classList.remove('outLink4')
        cursor.current.classList.add('onLink4')
    }
    const handleLeave = () => {
        cursor.current.classList.add('outLink4')
        cursor.current.classList.remove('onLink4')
        setTimeout(() => {
            cursor.current.classList.remove('outLink4')
        }, 1000);
    }
        
   

    return (
        <FormWrapper onSubmit={handleSubmit} onMouseMove={handleEnter} onMouseLeave={handleLeave}>
            <TextField
                required 
                id="standard-required" 
                label="Nume" 
                inputProps={{ maxLength: 24 }}
                color="primary" 
                fullWidth 
                value={name}
                onChange={(e) => setName(e.target.value)}
            />
            <TextField
                id="standard-multiline-static"
                label="Mesaj"
                multiline
                rows={6}
                inputProps={{ maxLength: 1000 }}
                margin="dense"
                color="primary"
                required
                spellCheck={false}
                value={message}
                onChange={(e) => setMessage(e.target.value)}
            />
            <Info><i>{message.length}</i>/1000</Info>

            <Wrapper>
                <FormControlLabel
                control={<Checkbox 
                checked={asPublic} 
                color="primary" 
                onChange={() => setAsPublic(!asPublic)} 
                name="checkbox" 
                />}
                label="Postează ca public"
                />
                <Box component="fieldset"  borderColor="transparent">
                    <MyRating name="review stars" value={rating} onChange={(e, newValue) => setRating(newValue)}/>
                </Box>
            </Wrapper>

            <Button disabled={disabled}
                type="submit"
                variant="contained"
                color="primary"
                endIcon={<StarIcon />}
            >
                Adaugă recenzie
            </Button>
        </FormWrapper>
    )
}

const FormWrapper = styled.form`
    display: flex;
    flex-direction: column;
    margin: 100px auto;
    width: 700px;
    max-width: 90vw;
    flex: 1;
    border-radius: 5px;
    input, textarea {
        color: #303030 !important;
    }
    label {
        color: #6e6e6e;
    }
    button {
        color: #f3f3f3;
        background-image: linear-gradient(45deg, var(--cbd), var(--cbl));
        width: 200px;
        height: 40px;
        align-self: flex-end;
        &:hover {
            background-image: linear-gradient(125deg, var(--cbd), var(--cbd));
            animation: bounce 2s both;
            @keyframes bounce { 
                0%, 30%, 50%, 80%, 100% {
                transform: translateY(0);
                } 
                20% {
                    transform: translateY(-7px);
                }
                40% {
                    transform: translateY(-5px);
                } 
                60% {
                    transform: translateY(-2px);
                } 
            }
        }
        @media screen and (max-width: 500px) {
            width: 100%;
        }
    }
`
const Wrapper = styled.div`
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 20px;
`
const Info = styled.small`
    color: grey;
`
const MyRating = styled(Rating)`
    margin-right: -5px;
    >label {
        color: #ffe600;
    }
`