import { Box } from '@material-ui/core'
import React from 'react'
import styled from 'styled-components'
import Rating from '@material-ui/lab/Rating';
import { forwardRef } from 'react';

const ClientReviewCard = forwardRef(({review}, ref) => {
    return (
        <Container ref={ref}>
            <Description>{review.data.message}</Description>
            <DateWrapper>{new Date(review.data.timestamp?.toDate()).toLocaleString('ro')}</DateWrapper>
            <Wrapper>
                <Avatar src={review.data.photo} alt="client review image"/>
                <Name>{review.data.name}</Name>
            </Wrapper>
            <StarsWrapper>
                <Box component="fieldset"  borderColor="transparent">
                    <CardRating name="show rating" value={review.data.rating} />
                </Box>
            </StarsWrapper>
        </Container>
    )
})
export default ClientReviewCard 

const Container = styled.div`
    margin: 20px;
    height: 400px;
    border: 1px solid grey;
    width: 300px;
    background-color: #000000c5;
    border-radius: 5px;
    padding: 20px;
    position: relative;
    display: flex;
    flex-direction: column;
    box-shadow: 0 5px 10px #000000a4;
    animation: floating 5s infinite alternate linear;
    &:hover {
        >div>img {
            z-index: -1;
        }
    }
    @keyframes floating {
        to {
            transform: translateY(-30px);
        }
    }
    &:nth-child(1) {
        animation-delay: 4s;
    }
    &:nth-child(3) {
        animation-delay: 2s;
    }
    @media screen and (max-width: 900px) {
        animation: none;
    }
`
const Description = styled.p`
    font-size: 0.9rem;
    color: white;
    position: relative;
    text-align: justify;
    max-height: 280px;
    overflow: scroll;
    &::-webkit-scrollbar {
        width: 0px;
    }
`
const DateWrapper = styled.small`
    font-size: 0.6rem;
    color: lightgray;
    text-align: right;
`
const Wrapper = styled.div`
    display: flex;
    gap: 30px;
    align-items: center;
    position: absolute;
    bottom: 20px;
    left: -50px;
    @media screen and (max-width: 400px) {
        left: -20px;
    }
`
const Avatar = styled.img`
    z-index: 1;
    width: 100px;
    box-shadow: 0 2px 10px #00000067;
`
const Name = styled.p`
    color: white;
    font-family: var(--fssp);
    font-size: var(--sf);
    margin-top: 20px;
`
const StarsWrapper = styled.div`
    position: absolute;
    bottom: 10px;
    right: 10px;
`
const CardRating = styled(Rating)`
    pointer-events: none;
    >label {
        color: #ffe600;
    }
`

