import React, { useRef } from 'react';
import { useEffect } from 'react';
import { useState } from 'react';
import { useDispatch } from 'react-redux';
import { useSelector } from 'react-redux';
import { BrowserRouter as Router, Redirect, Route, Switch } from 'react-router-dom'
import { auth, db } from './components/firebase';
import Navbar from './components/Navbar';
import { selectErrorMessage, selectShowError } from './features/errorSlice';
import { login, selectAdmin, selectUser } from './features/userSlice';
import Homepage from './pages/Homepage/Homepage';
import Shoppage from './pages/Shoppage/Shoppage';
import Adminpage from './pages/Adminpage/Adminpage';
import Loginpage from './pages/Loginpage/Loginpage';
import PopupMessage from './components/PopupMessage';
import firebase from 'firebase'
import Footer from './components/Footer';
import Cursor from './components/Cursor';
import ToTop from './components/ToTop';
import Progressbar from './components/Progressbar';
import GoogleAds from './components/GoogleAds';


function App() {
  const user = useSelector(selectUser)
  const admin = useSelector(selectAdmin)
  const dispatch = useDispatch()
  const [owner, setOwner] = useState(false)
  const showErrorIsOpen = useSelector(selectShowError)
  const error = useSelector(selectErrorMessage)
  const cursor = useRef()
  const outline = useRef()


  useEffect(() => {
    auth.onAuthStateChanged(user => {
      if (user) {
        dispatch(login({
          displayName: user.displayName,
          email: user.email,
          photoUrl: user.photoURL
        }))
        if (user.email === admin) {
          setOwner(true)
        } else {
          const userDoc = user?.email
          db.collection('cm-users').doc(userDoc).set({
            name: user.displayName,
            email: user.email,
            timestamp: firebase.firestore.FieldValue.serverTimestamp(),
          })
        }
      }
    })
  }, [dispatch, admin])



  return (
    <div>
      <Cursor cursor={cursor} outline={outline} />
      <ToTop />
      <Progressbar />

      <Router >
        <Navbar user={user} owner={owner} setOwner={setOwner} cursor={cursor} />
        <Switch>
          <Route path="/" exact>
            <Homepage cursor={cursor} outline={outline} />
          </Route>

          {owner ?
            <Route path="/admin" exact>
              <Adminpage />
            </Route>
            :
            <Route path="/cumpara" exact>
              <Shoppage />
            </Route>
          }


          <Route path="/login">
            {user ?
              <Redirect from="/login" to="/" />
              :
              <Loginpage />
            }
          </Route>
        </Switch>

        <GoogleAds />

        <Footer />
      </Router>
      {showErrorIsOpen && <PopupMessage error={error} />}
    </div>
  );
}

export default App;


