import React from 'react'
import { useEffect } from 'react'
import styled from 'styled-components'


export default function Bubble({refr, outline}) {
    let xAxys = Math.floor(Math.random() * document.body.scrollWidth)
    let yAxys = Math.floor(Math.random() * 4000)

    useEffect(() => {
        function paralax() {
            refr.current.style.transform = `translateY(${Math.floor(refr.current.getBoundingClientRect().y / 20 - window.innerHeight / 10)}px)`
        }

        window.addEventListener('scroll', paralax)

        return () => window.removeEventListener('scroll', paralax)

    }, [refr])

    const handleEnter = () => {
        outline.current.classList.remove('outBubble')
        outline.current.classList.add('onBubble')
    }
    const handleLeave = () => {
        outline.current.classList.add('outBubble')
        outline.current.classList.remove('onBubble')
        setTimeout(() => {
            outline.current.classList.remove('outBubble')
        }, 1000);
    }

    return (
        <Container ref={refr} style={{top: yAxys, left: xAxys}} onMouseEnter={handleEnter} onMouseLeave={handleLeave}>
            
        </Container>
    )
}


const Container = styled.div`
    pointer-events: all;
    width: 5vh;
    height: 5vh;
    border-radius: 50%;
    border: 3px solid var(--cgd);
    position: absolute;
    transition: all 0.3s ease;
    opacity: 0.2;
    &::after {
        content: '';
        position: absolute;
        top: 50%;
        left: 50%;
        width: 0;
        height: 0;
        border-radius: 50%;
        background-color: var(--cgd);
    }
    &:hover::after {
        width: 102%;
        height: 102%;
        top: 0;
        left: 0;
        animation: anim 2s linear infinite;
        transform: translate(-50%, -50%);
        @keyframes anim { 
            0%, 20%, 50%, 70%, 100% {
                transform: scale(0);
            } 
            40% {
                transform: scale(1);
            } 
            60% {
                transform: scale(0.7);
            } 
            80% {
                transform: scale(0.4);
            }
        }
    }
   
`